                        },
                    }
                },
            },
            scales: {
                current: {
                    position: 'left',
                    beginAtZero: true,
                    ticks: {
                        color: this.$styleStore.operatingPoints.currentGraph.color,
                        font: { size: 11, weight: '500' },
                        padding: 4,
                    },
                    grid: {
                        color: 'rgba(177, 138, 234, 0.12)',
                        drawBorder: false,
                        lineWidth: 1,
                    },
                    border: { display: false },
                },
                voltage: {
